        pcvalueCache pcvalueCache{};
        dlogPerM dlogPerM{};
        mOS mOS{};
        chacha8rand::State chacha8{};
        uint64_t cheaprand{};
        // Up to 10 locks held by this m, maintained by the lock ranking code.
        int locksHeldLen{};
        gocpp::array<heldLockInfo, 10> locksHeld{};

